INSERT INTO team_tactic_setups VALUES(1,'2025-26','FC26','optimal','4-2-3-1','Short Passing','High',68,NULL,'Emery 25/26: positional short build-up from the back (Martínez sweeper + Pau Torres BPD carrying out), famously high defensive line with offside trap; Aggressive rejected because Villa''s block is structured mid-high press, not constant counter-press. Line 68 = upper-mid of the High band. Pairs with player_role_map kind=''optimal'' (16 rows: XI + bench).','MEDIUM — team-setting mapping is an initial hypothesis from analysed build-up/line traits; not yet validated in-game. Validate by creating the tactic in FC26, saving the tactic_code here, and comparing in-game heatmaps vs measured ones.');
